package ru.memearena.user.api;
import io.swagger.v3.oas.annotations.Operation; import jakarta.servlet.http.HttpServletRequest; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.security.core.annotation.AuthenticationPrincipal; import org.springframework.web.bind.annotation.*; import ru.memearena.ratelimit.RateLimiterService; import ru.memearena.security.*; import ru.memearena.user.application.UserProfileService; import ru.memearena.scout.application.*; import ru.memearena.scout.api.ScoutDtos.*; import java.time.*; import java.util.*;
@RestController @RequestMapping("/api/v1/users") public class UserProfileController { private final UserProfileService service; private final IpAddressService ips; private final RateLimiterService limits; private final ScoutService scout; private final AchievementService achievements; private final Clock clock; public UserProfileController(UserProfileService service,IpAddressService ips,RateLimiterService limits,ScoutService scout,AchievementService achievements,Clock clock){this.service=service;this.ips=ips;this.limits=limits;this.scout=scout;this.achievements=achievements;this.clock=clock;} @PostMapping("/guest") @Operation(summary="Create guest user") public ResponseEntity<CreateGuestUserResponse> create(@Valid @RequestBody CreateGuestUserRequest r,HttpServletRequest req){String ipHash=ips.hashIp(ips.clientIp(req)); limits.check("guest",ipHash,5,3600); var x=service.createGuest(r.nickname(),r.installationId(),ipHash); return ResponseEntity.status(HttpStatus.CREATED).body(new CreateGuestUserResponse(enrich(x.user()),new GuestSessionResponse(x.accessToken(),x.expiresAt())));} @GetMapping("/me") public UserProfileResponse me(@AuthenticationPrincipal AuthenticatedUserPrincipal p){return enrich(service.get(p.userId()));} @PostMapping("/me/logout") @ResponseStatus(HttpStatus.NO_CONTENT) public void logout(@AuthenticationPrincipal AuthenticatedUserPrincipal p){service.logout(p.sessionId());} @GetMapping("/{userId}") @Operation(summary="Get public user profile") public UserProfileResponse get(@PathVariable UUID userId){return enrich(service.get(userId));} private UserProfileResponse enrich(ru.memearena.user.domain.UserProfile u){var s=scout.stats(u.getId(),Instant.now(clock)); var as=achievements.byUser(u.getId()).stream().map(a->{var d=AchievementService.CATALOG.get(a.getAchievementCode()); return new AchievementResponse(a.getAchievementCode(),d==null?a.getAchievementCode():d.title(),d==null?"":d.description(),a.getUnlockedAt());}).toList(); return new UserProfileResponse(u.getId(),u.getNickname(),u.getVotesCount(),u.getSubmittedMemesCount(),u.status(),ScoutStatsResponse.from(s),as,u.getCreatedAt());} }
